+			Priority:     issue.Priority,
+			BlockerCount: stats.InDegree[issue.ID],
+			UpdatedAt:    issue.UpdatedAt,
+		}
+	}
+
+	// Compute hash from the exact same issues used for metrics
+	hash := analysis.ComputeDataHash(l.issues)
